document.addEventListener("DOMContentLoaded",function(){const e=document.querySelectorAll('a[href^="#"]:not(a[href="#"]), .anchor[href^="#"], [class*="anchor"][href^="#"]');e.forEach(e=>{e.addEventListener("click",function(e){e.preventDefault();const t=this.getAttribute("href").substring(1);if(!t)return;const n=document.getElementById(t);if(!n)return;n.scrollIntoView({behavior:"smooth",block:"center",inline:"nearest"}),history.replaceState(null,null,"#"+t)})})});function handleInitialHash(){if(!location.hash)return;let n=location.hash.substring(1),e=n;if(n.includes("%"))try{e=decodeURIComponent(n)}catch(e){console.error("decode 失败",e)}if(!e)return;let t=document.getElementById(e);!t&&!e.startsWith("-")&&(t=document.getElementById("-"+e)),t?setTimeout(()=>{console.log("找到元素，执行滚动:",t),t.scrollIntoView({behavior:"smooth",block:"center"})},800):(alert("未找到"),console.log("未找到 id:",e))}window.addEventListener("pageshow",function(){handleInitialHash()})